#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int Arr[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &Arr[i]);
        }
        int K1, K2, Z, Y;
        scanf("%d %d %d %d", &K1, &K2, &Z, &Y);
        qsort(Arr, N, sizeof(int), compare);
        int count = 0;
        for (int i = 0; i < N; i++) {
            if (Arr[i] == Z) {
                count++;
            }
        }
        if (count >= Y) {
            printf("YES\n");
            continue;
        }
        for (int i = 0; i < N; i++) {
            if (Arr[i] < Z) {
                Arr[i] += K2;
            } else {
                Arr[i] -= K1;
            }
        }
        count = 0;
        for (int i = 0; i < N; i++) {
            if (Arr[i] == Z) {
                count++;
            }
        }
        if (count >= Y) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

